mapper.select:
SELECT eg.SEQ, eg.RESUME_SEQ, eg.EVS_TYPE, GET_CODE_NAME(eg.EVS_TYPE, #{lang, jdbcType=VARCHAR}) AS EVS_TYPE_NAME, eg.EVS_GRADE, GET_CODE_NAME(eg.EVS_GRADE, #{lang, jdbcType=VARCHAR}) AS EVS_GRADE_ORIGINAL, DECODE(GET_CODE_NAME(eg.EVS_GRADE, #{lang, jdbcType=VARCHAR}), 'A', 'EX', 'B', 'VG', 'C', 'GD', 'D', 'NI', 'E', 'UN') AS EVS_GRADE_NAME, eg.IS_INCLUDE, TO_CHAR(eg.START_SCORE) AS START_SCORE, TO_CHAR(eg.END_SCORE) AS END_SCORE, TO_CHAR(eg.SCORE) AS SCORE, eg.REMARK, eg.ACTIVITY, TO_CHAR(eg.ORDERNO) AS ORDER_NO, TO_CHAR(eg.DISTRIBUTION_RATE) AS DISTRIBUTION_RATE, TO_CHAR(eg.CREATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DATE, GET_UPDATED_INFO(eg.CREATED_BY) || ' ' || eg.CREATED_IP AS CREATED_BY, TO_CHAR(eg.UPDATE_DATE, 'YYYY-MM-DD HH24:MI') AS UPDATE_DATE, GET_UPDATED_INFO(eg.UPDATED_BY) || ' ' || eg.UPDATED_IP AS UPDATED_BY FROM EVS_GRADE eg WHERE ACTIVITY != 2
AND eg.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
ORDER BY TO_NUMBER(eg.SEQ)

mapper.delete:
UPDATE EVS_GRADE
SET UPDATE_DATE = SYSDATE,
    UPDATED_BY = #{adminID, jdbcType=VARCHAR},
    ACTIVITY = 2,
    UPDATED_IP = #{adminIP, jdbcType=VARCHAR}
WHERE SEQ     = #{seq,    jdbcType=VARCHAR}
